const express = require('express');
const projectsRoutes = require('./modules/projects/routes');
const membersRoutes = require('./modules/members/routes');
const tasksRoutes = require('./modules/tasks/routes');
const commentsRoutes = require('./modules/comments/routes');

const app = express();
app.use(express.json());

app.get('/health', (req, res) => {
  res.json({ ok: true });
});

app.use('/projects', projectsRoutes);
app.use('/projects/:projectId/members', membersRoutes);
app.use('/projects/:projectId/tasks', tasksRoutes);
app.use('/projects/:projectId/tasks/:taskId/comments', commentsRoutes);

module.exports = app;

const sendError = (res, status, code, message) => {
  res.status(status).json({ error: { code, message } });
};

module.exports = { sendError };

const { randomUUID } = require('node:crypto');

const generateId = () => {
  return randomUUID();
};

module.exports = { generateId };

const express = require('express');
const projectService = require('./service');
const { sendError } = require('../../lib/errors');

const router = express.Router();

router.post('/', (req, res) => {
  const { name } = req.body;
  if (!name) {
    return sendError(res, 400, 'INVALID_NAME', 'Name is required');
  }
  const project = projectService.createProject(name);
  res.status(201).json({ project });
});

router.get('/', (req, res) => {
  const projects = projectService.getAllProjects();
  res.json({ projects });
});

module.exports = router;

const { generateId } = require('../../lib/id');

let projects = [];

const createProject = (name) => {
  const project = { id: generateId(), name, members: [], tasks: [] };
  projects.push(project);
  return project;
};

const getAllProjects = () => {
  return projects;
};

module.exports = { createProject, getAllProjects };

const express = require('express');
const memberService = require('./service');
const projectService = require('../projects/service');
const { sendError } = require('../../lib/errors');

const router = express.Router();

router.post('/', (req, res) => {
  const projectId = req.params.projectId;
  const { userId, role } = req.body;
  if (!userId || !role) {
    return sendError(res, 400, 'INVALID_BODY', 'UserId and role are required');
  }
  const project = projectService.getAllProjects().find(p => p.id === projectId);
  if (!project) {
    return sendError(res, 404, 'PROJECT_NOT_FOUND', 'Project not found');
  }
  const member = memberService.addMember(projectId, userId, role);
  res.status(201).json({ member });
});

module.exports = router;

const projectService = require('../projects/service');
const { generateId } = require('../../lib/id');

const addMember = (projectId, userId, role) => {
  const project = projectService.getAllProjects().find(p => p.id === projectId);
  if (!project) return null;
  const member = { id: generateId(), userId, role };
  project.members.push(member);
  return member;
};

module.exports = { addMember };

const express = require('express');
const taskService = require('./service');
const projectService = require('../projects/service');
const { sendError } = require('../../lib/errors');

const router = express.Router();

router.post('/', (req, res) => {
  const projectId = req.params.projectId;
  const task = taskService.createTask(projectId);
  if (!task) {
    return sendError(res, 404, 'PROJECT_NOT_FOUND', 'Project not found');
  }
  res.status(201).json({ task });
});

router.get('/', (req, res) => {
  const projectId = req.params.projectId;
  const status = req.query.status;
  const tasks = taskService.getTasks(projectId, status);
  if (!tasks) {
    return sendError(res, 404, 'PROJECT_NOT_FOUND', 'Project not found');
  }
  res.json({ tasks });
});

router.patch('/:taskId', (req, res) => {
  const projectId = req.params.projectId;
  const taskId = req.params.taskId;
  const { status } = req.body;
  const task = taskService.updateTaskStatus(projectId, taskId, status);
  if (!task) {
    return sendError(res, 404, 'TASK_NOT_FOUND', 'Task not found');
  }
  res.json({ task });
});

module.exports = router;

const projectService = require('../projects/service');
const { generateId } = require('../../lib/id');

const createTask = (projectId) => {
  const project = projectService.getAllProjects().find(p => p.id === projectId);
  if (!project) return null;
  const task = { id: generateId(), status: 'todo' };
  project.tasks.push(task);
  return task;
};

const getTasks = (projectId, status) => {
  const project = projectService.getAllProjects().find(p => p.id === projectId);
  if (!project) return null;
  if (status) {
    return project.tasks.filter(t => t.status === status);
  }
  return project.tasks;
};

const updateTaskStatus = (projectId, taskId, newStatus) => {
  const project = projectService.getAllProjects().find(p => p.id === projectId);
  if (!project) return null;
  const task = project.tasks.find(t => t.id === taskId);
  if (!task || !['todo', 'done'].includes(newStatus)) return null;
  task.status = newStatus;
  return task;
};

module.exports = { createTask, getTasks, updateTaskStatus };

const express = require('express');
const commentService = require('./service');
const projectService = require('../projects/service');
const taskService = require('../tasks/service');
const { sendError } = require('../../lib/errors');

const router = express.Router();

router.post('/', (req, res) => {
  const projectId = req.params.projectId;
  const taskId = req.params.taskId;
  const { message } = req.body;
  if (!message) {
    return sendError(res, 400, 'INVALID_BODY', 'Message is required');
  }
  const task = taskService.getTasks(projectId).find(t => t.id === taskId);
  if (!task) {
    return sendError(res, 404, 'TASK_NOT_FOUND', 'Task not found');
  }
  const comment = commentService.addComment(taskId, message);
  res.status(201).json({ comment });
});

module.exports = router;

const taskService = require('../tasks/service');
const { generateId } = require('../../lib/id');

const addComment = (taskId, message) => {
  const task = taskService.getTasks().find(t => t.id === taskId);
  if (!task) return null;
  const comment = { id: generateId(), message };
  if (!task.comments) {
    task.comments = [];
  }
  task.comments.push(comment);
  return comment;
};

module.exports = { addComment };
